class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def buildTree(self, preorder: list[int], inorder: list[int]) -> TreeNode:
        if not preorder or not inorder:
            return None

        inorder_map = {val: i for i, val in enumerate(inorder)}

        def build(preorder_start, preorder_end, inorder_start, inorder_end):
            if preorder_start > preorder_end or inorder_start > inorder_end:
                return None

            root_val = preorder[preorder_start]
            root = TreeNode(root_val)

            root_inorder_index = inorder_map[root_val]

            left_subtree_size = root_inorder_index - inorder_start

            root.left = build(
                preorder_start + 1,
                preorder_start + left_subtree_size,
                inorder_start,
                root_inorder_index - 1
            )

            root.right = build(
                preorder_start + left_subtree_size + 1,
                preorder_end,
                root_inorder_index + 1,
                inorder_end
            )

            return root

        return build(0, len(preorder) - 1, 0, len(inorder) - 1)
